def has_close_elements(numbers, threshold):
    if len(numbers) < 2:
        return False
    if threshold <= 0:
        return False
    sorted_nums = sorted(numbers)
    for i in range(len(sorted_nums) - 1):
        if sorted_nums[i + 1] - sorted_nums[i] < threshold:
            return True
    return False
